﻿using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using VagabondK.Protocols.Channels;

namespace VagabondK.Protocols.LSElectric.FEnet
{
    /// <summary>
    /// LS ELECTRIC(구 LS산전) FEnet 프로토콜 메시지
    /// </summary>
    public abstract class FEnetMessage : IProtocolMessage
    {
        internal static readonly byte[] zero = new byte[] { 0, 0 };
        internal static readonly byte[] one = new byte[] { 1, 0 };

        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="command">커맨드</param>
        /// <param name="dataType">커맨드 데이터 타입</param>
        internal FEnetMessage(FEnetCommand command, FEnetDataType dataType)
        {
            Command = command;
            DataType = dataType;
        }

        private ushort? invokeID;

        private byte[] frameData;

        /// <summary>
        /// 요청과 응답 메시지간의 순서를 구별하기 위한 ID
        /// </summary>
        public ushort? InvokeID { get => invokeID; set => SetProperty(ref invokeID, value); }

        /// <summary>
        /// 통신 메시지의 소스. 클라이언트(HMI): 0x33, 서버(PLC): 0x11
        /// </summary>
        public abstract byte SourceOfFrame { get; }


        /// <summary>
        /// 커맨드
        /// </summary>
        public FEnetCommand Command { get; }

        /// <summary>
        /// 커맨드 데이터 타입
        /// </summary>
        public FEnetDataType DataType { get; }

        /// <summary>
        /// 내부 프레임 데이터 무효화
        /// </summary>
        protected void InvalidateFrameData()
        {
            lock (this)
            {
                frameData = null;
            }
        }

        /// <summary>
        /// 속성 값 설정
        /// </summary>
        /// <typeparam name="TProperty">속성 형식</typeparam>
        /// <param name="target">설정할 멤버 변수</param>
        /// <param name="value">새로 설정하는 값</param>
        /// <returns>설정 여부</returns>
        protected bool SetProperty<TProperty>(ref TProperty target, TProperty value)
        {
            lock (this)
            {
                if (!EqualityComparer<TProperty>.Default.Equals(target, value))
                {
                    target = value;
                    frameData = null;
                    return true;
                }
                return false;
            }
        }

        internal static IEnumerable<byte> WordToLittleEndianBytes(ushort value) => BitConverter.IsLittleEndian ? BitConverter.GetBytes(value) : BitConverter.GetBytes(value).Reverse();
        internal static IEnumerable<byte> ValueToLittleEndianBytes(short value) => BitConverter.IsLittleEndian ? BitConverter.GetBytes(value) : BitConverter.GetBytes(value).Reverse();
        internal static IEnumerable<byte> ValueToLittleEndianBytes(int value) => BitConverter.IsLittleEndian ? BitConverter.GetBytes(value) : BitConverter.GetBytes(value).Reverse();
        internal static IEnumerable<byte> ValueToLittleEndianBytes(long value) => BitConverter.IsLittleEndian ? BitConverter.GetBytes(value) : BitConverter.GetBytes(value).Reverse();
        internal static ushort ReadWord(Channel channel, List<byte> buffer)
        {
            var result = channel.Read(2, 0).ToArray();
            buffer.AddRange(result);
            return BitConverter.IsLittleEndian ? BitConverter.ToUInt16(result, 0) : BitConverter.ToUInt16(result.Reverse().ToArray(), 0);
        }
        internal static FEnetDataType ToFEnetDataType(DataType dataType)
        {
            switch (dataType)
            {
                case LSElectric.DataType.Bit:
                    return FEnetDataType.Bit;
                case LSElectric.DataType.Byte:
                    return FEnetDataType.Byte;
                case LSElectric.DataType.Word:
                    return FEnetDataType.Word;
                case LSElectric.DataType.DoubleWord:
                    return FEnetDataType.DoubleWord;
                case LSElectric.DataType.LongWord:
                    return FEnetDataType.LongWord;
                default:
                    return FEnetDataType.Continuous;
            }
        }
        internal static DataType ToDataType(FEnetDataType dataType)
        {
            switch (dataType)
            {
                case FEnetDataType.Bit:
                    return LSElectric.DataType.Bit;
                case FEnetDataType.Byte:
                    return LSElectric.DataType.Byte;
                case FEnetDataType.Word:
                    return LSElectric.DataType.Word;
                case FEnetDataType.DoubleWord:
                    return LSElectric.DataType.DoubleWord;
                case FEnetDataType.LongWord:
                    return LSElectric.DataType.LongWord;
                default:
                    return LSElectric.DataType.Unknown;
            }
        }

        /// <summary>
        /// 데이터 프레임 생성
        /// </summary>
        /// <returns>데이터의 직렬화 된 바이트 열거</returns>
        protected virtual IEnumerable<byte> OnCreateDataFrame() { yield break; }

        /// <summary>
        /// 직렬화
        /// </summary>
        /// <param name="companyID">Company ID, 메시지의 헤더. LSIS-XGT나 LGIS-GLOFA를 사용함.</param>
        /// <param name="useChecksum">Application Header에 체크섬 사용 여부</param>
        /// <returns>직렬화 된 바이트 열거</returns>
        public virtual IEnumerable<byte> Serialize(string companyID, bool useChecksum)
        {
            lock (this)
            {
                if (frameData == null)
                {
                    var dataFrame = OnCreateDataFrame().ToArray();

                    List<byte> byteList = new List<byte>(Encoding.ASCII.GetBytes(companyID).Take(10));
                    if (byteList.Count < 10)
                        byteList.AddRange(Enumerable.Repeat((byte)0, 10 - byteList.Count));
                    byteList.Add(0);
                    byteList.Add(0);
                    byteList.Add(0);
                    byteList.Add(SourceOfFrame);
                    byteList.AddRange(WordToLittleEndianBytes(invokeID ?? 0));
                    byteList.AddRange(WordToLittleEndianBytes((ushort)dataFrame.Length));
                    byteList.Add(0);
                    byteList.Add((byte)(useChecksum ? byteList.Sum(b => b) % 256 : 0x00));
                    byteList.AddRange(dataFrame);
                    frameData = byteList.ToArray();
                }
                return frameData;
            }
        }
    }
}

﻿using System;
using System.Collections.Generic;
using System.Text;

namespace VagabondK.Protocols.LSElectric.FEnet
{
    /// <summary>
    /// LS ELECTRIC(구 LS산전) FEnet 프로토콜 커맨드
    /// </summary>
    public enum FEnetCommand : ushort
    {
        /// <summary>
        /// 읽기
        /// </summary>
        Read = 0x0054,
        /// <summary>
        /// 쓰기
        /// </summary>
        Write = 0x0058,
    }

    /// <summary>
    /// LS ELECTRIC(구 LS산전) FEnet 프로토콜 커맨드의 데이터 타입
    /// </summary>
    public enum FEnetDataType : ushort
    {
        /// <summary>
        /// 비트
        /// </summary>
        Bit = 0x0000,
        /// <summary>
        /// 바이트
        /// </summary>
        Byte = 0x0001,
        /// <summary>
        /// 워드, 2바이트
        /// </summary>
        Word = 0x0002,
        /// <summary>
        /// 더블 워드, 4바이트
        /// </summary>
        DoubleWord = 0x0003,
        /// <summary>
        /// 롱 워드, 8바이트
        /// </summary>
        LongWord = 0x0004,
        /// <summary>
        /// 연속 데이터, 가변 길이
        /// </summary>
        Continuous = 0x0014,
    }

    /// <summary>
    /// LS ELECTRIC(구 LS산전) FEnet 프로토콜 NAK 에러 코드
    /// </summary>
    public enum FEnetNAKCode : ushort
    {
        /// <summary>
        /// 알 수 없음
        /// </summary>
        Unknown = 0x0000,

        /// <summary>
        /// 요청 블록 수 초과(최대 16개)
        /// </summary>
        OverRequestReadBlockCount = 0x0001,

        /// <summary>
        /// 데이터 타입 오류
        /// </summary>
        DeviceVariableTypeError = 0x0002,

        /// <summary>
        /// 지원하지 않는 디바이스 메모리
        /// </summary>
        IlegalDeviceMemory = 0x0003,

        /// <summary>
        /// 디바이스 요구 영역 초과
        /// </summary>
        OutOfRangeDeviceVariable = 0x0004,

        /// <summary>
        /// 개별 블록 데이터 길이 초과(최대 1400바이트)
        /// </summary>
        OverDataLengthIndividual = 0x0005,

        /// <summary>
        /// 블록별 총 데이터 길이 초과(최대 1400바이트)
        /// </summary>
        OverDataLengthTotal = 0x0006,

        /// <summary>
        /// 잘못된 CompanyID
        /// </summary>
        IlegalCompanyID = 0x0075,

        /// <summary>
        /// 프레임 헤더의 Length 가 잘못됨
        /// </summary>
        IlegalLength = 0x0076,

        /// <summary>
        /// 프레임 헤더의 Chacksum이 잘못됨
        /// </summary>
        ErrorChacksum = 0x0076,

        /// <summary>
        /// 명령어 오류
        /// </summary>
        IlegalCommand = 0x0077,
    }

    /// <summary>
    /// LS ELECTRIC(구 LS산전) FEnet 통신 오류 코드
    /// </summary>
    public enum FEnetCommErrorCode
    {
        /// <summary>
        /// Not Defined
        /// </summary>
        NotDefined,
        /// <summary>
        /// 응답의 길이 정보와 실제 길이가 일치하지 않음.
        /// </summary>
        ResponseLengthDoNotMatch,
        /// <summary>
        /// 요청과 응답의 커맨드가 일치하지 않음.
        /// </summary>
        ResponseCommandDoNotMatch,
        /// <summary>
        /// 요청과 응답의 데이터 타입이 일치하지 않음.
        /// </summary>
        ResponseDataTypeDoNotMatch,
        /// <summary>
        /// 요청과 응답의 데이터 블록 개수가 일치하지 않음.
        /// </summary>
        ResponseDataBlockCountDoNotMatch,
        /// <summary>
        /// 요청과 응답의 데이터 개수가 일치하지 않음.
        /// </summary>
        ResponseDataCountNotMatch,
        /// <summary>
        /// 잘못된 데이터 개수.
        /// </summary>
        ErrorDataCount,
        /// <summary>
        /// BCC 오류
        /// </summary>
        ErrorChecksum,
        /// <summary>
        /// 응답 타임아웃
        /// </summary>
        ResponseTimeout
    }
}

﻿using System;
using System.Collections;
using System.Collections.Generic;
using System.Linq;

namespace VagabondK.Protocols.LSElectric.FEnet
{
    /// <summary>
    /// LS ELECTRIC(구 LS산전) FEnet 프로토콜 요청 메시지
    /// </summary>
    public abstract class FEnetRequest : FEnetMessage, IRequest<FEnetCommErrorCode>, ICloneable
    {
        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="command">커맨드</param>
        /// <param name="dataType">커맨드 데이터 타입</param>
        protected FEnetRequest(FEnetCommand command, FEnetDataType dataType) : base(command, dataType) { }

        private bool? useHexBitIndex;

        /// <summary>
        /// 통신 메시지의 소스. 클라이언트(HMI): 0x33
        /// </summary>
        public override byte SourceOfFrame => 0x33;

        /// <summary>
        /// 블록 수
        /// </summary>
        public abstract ushort BlockCount { get; }

        /// <summary>
        /// 비트 변수의 인덱스를 16진수로 통신할지 여부를 결정합니다.
        /// P, M, L, K, F 이면서 Bit일 경우 워드 단위 인덱스와 함께 비트 자리수를 16진수로 전송합니다.
        /// 그 외에는 인덱스가 .으로 나누어져있고 Bit일 경우 마지막 자리만 16진수로 전송합니다.
        /// 이 속성을 null로 설정하면 FEnetClient의 UseHexBitIndex 값을 따릅니다.
        /// XGB PLC에서 비트를 읽거나 쓸 때 엉뚱한 비트가 읽히거나 쓰인다면 true로 설정해서 테스트 해보시기 바랍니다.
        /// '라이스'님의 제보로 추가되었으며, '박일두'님의 제보로 추가 개선된 옵션입니다. 감사합니다.
        /// </summary>
        public bool? UseHexBitIndex { get => useHexBitIndex; set => SetProperty(ref useHexBitIndex, value); }

        /// <summary>
        /// 요청 메시지 복제
        /// </summary>
        /// <returns>복제된 요청 메시지</returns>
        public abstract object Clone();

        /// <summary>
        /// 데이터 프레임 생성
        /// </summary>
        /// <returns>데이터의 직렬화 된 바이트 열거</returns>
        protected override IEnumerable<byte> OnCreateDataFrame()
            => WordToLittleEndianBytes((ushort)Command).Concat(WordToLittleEndianBytes((ushort)DataType)).Concat(zero).Concat(WordToLittleEndianBytes(BlockCount));
    }

    /// <summary>
    /// 디바이스 읽기 요청
    /// </summary>
    public abstract class FEnetReadRequest : FEnetRequest
    {
        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="dataType">커맨드 데이터 타입</param>
        protected FEnetReadRequest(FEnetDataType dataType) : base(FEnetCommand.Read, dataType) { }
    }

    /// <summary>
    /// 개별 디바이스 변수 읽기 요청
    /// </summary>
    public class FEnetReadIndividualRequest : FEnetReadRequest, IList<DeviceVariable>
    {
        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="dataType">커맨드 데이터 타입</param>
        public FEnetReadIndividualRequest(DataType dataType) : this(dataType, null as IEnumerable<DeviceVariable>) { }

        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="dataType">커맨드 데이터 타입</param>
        /// <param name="deviceVariables">디바이스 변수 목록</param>
        public FEnetReadIndividualRequest(DataType dataType, IEnumerable<DeviceVariable> deviceVariables) : base(ToFEnetDataType(dataType))
        {
            if (deviceVariables == null)
                this.deviceVariables = new List<DeviceVariable>();
            else
                this.deviceVariables = new List<DeviceVariable>(deviceVariables);
        }

        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="dataType">커맨드 데이터 타입</param>
        /// <param name="deviceVariable">디바이스 변수</param>
        /// <param name="moreDeviceVariables">추가 디바이스 변수 목록</param>
        public FEnetReadIndividualRequest(DataType dataType, DeviceVariable deviceVariable, params DeviceVariable[] moreDeviceVariables)
            : this(dataType, new DeviceVariable[] { deviceVariable }.Concat(moreDeviceVariables)) { }

        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="deviceVariable">디바이스 변수</param>
        /// <param name="moreDeviceVariables">추가 디바이스 변수 목록</param>
        public FEnetReadIndividualRequest(DeviceVariable deviceVariable, params DeviceVariable[] moreDeviceVariables)
            : this(deviceVariable.DataType, new DeviceVariable[] { deviceVariable }.Concat(moreDeviceVariables)) { }

        /// <summary>
        /// 블록 수
        /// </summary>
        public override ushort BlockCount => (ushort)deviceVariables.Count;

        /// <summary>
        /// 요청 메시지 복제
        /// </summary>
        /// <returns>복제된 요청 메시지</returns>
        public override object Clone() => new FEnetReadIndividualRequest(ToDataType(DataType), deviceVariables) { InvokeID = InvokeID, UseHexBitIndex = UseHexBitIndex };

        private readonly List<DeviceVariable> deviceVariables;

        /// <summary>
        /// 디바이스 변수 개수
        /// </summary>
        public int Count => deviceVariables.Count;

        /// <summary>
        /// 디바이스 변수 컬렉션이 읽기 전용인지 여부를 나타내는 값을 가져옵니다.
        /// </summary>
        public bool IsReadOnly => ((ICollection<DeviceVariable>)deviceVariables).IsReadOnly;

        /// <summary>
        /// 디바이스 변수가 존재하는지 여부를 가져옵니다.
        /// </summary>
        /// <param name="deviceVariable">디바이스 변수</param>
        /// <returns>디바이스 변수 존재 여부</returns>
        public bool Contains(DeviceVariable deviceVariable) => deviceVariables.Contains(deviceVariable);

        /// <summary>
        /// 디바이스 변수의 순서상 위치를 가져옵니다.
        /// </summary>
        /// <param name="deviceVariable">디바이스 변수</param>
        /// <returns>디바이스 변수의 순서상 위치</returns>
        public int IndexOf(DeviceVariable deviceVariable) => deviceVariables.IndexOf(deviceVariable);

        /// <summary>
        /// 디바이스 변수를 반복하는 열거자를 반환합니다.
        /// </summary>
        /// <returns>디바이스 변수를 반복하는 열거자</returns>
        public IEnumerator<DeviceVariable> GetEnumerator() => deviceVariables.GetEnumerator();

            InvalidateFrameData();
        }

        /// <summary>
        /// 디바이스 변수 값을 추가합니다.
        /// </summary>
        /// <param name="item">디바이스 변수/디바이스 값 쌍</param>
        public void Add(KeyValuePair<DeviceVariable, DeviceValue> item)
        {
            ((ICollection<KeyValuePair<DeviceVariable, DeviceValue>>)valueDictionary).Add(item);
            InvalidateFrameData();
        }

        /// <summary>
        /// 디바이스 변수 및 값을 제거합니다.
        /// </summary>
        /// <param name="deviceVariable">디바이스 변수</param>
        /// <returns>제거 여부</returns>
        public bool Remove(DeviceVariable deviceVariable)
        {
            var result = valueDictionary.Remove(deviceVariable);
            if (result) InvalidateFrameData();
            return result;
        }

        /// <summary>
        /// 디바이스 변수/디바이스 값 쌍을 제거합니다.
        /// </summary>
        /// <param name="item">디바이스 변수/디바이스 값 쌍</param>
        /// <returns>제거 여부</returns>
        public bool Remove(KeyValuePair<DeviceVariable, DeviceValue> item)
        {
            var result = ((ICollection<KeyValuePair<DeviceVariable, DeviceValue>>)valueDictionary).Remove(item);
            if (result) InvalidateFrameData();
            return result;
        }

        /// <summary>
        /// 데이터 프레임 생성
        /// </summary>
        /// <returns>데이터의 직렬화 된 바이트 열거</returns>
        protected override IEnumerable<byte> OnCreateDataFrame()
        {
            foreach (var b in base.OnCreateDataFrame()
                .Concat(valueDictionary.SelectMany(keyValuePair =>
                {
                    var deviceVariableBytes = keyValuePair.Key.ToBytes(UseHexBitIndex ?? false);
                    return WordToLittleEndianBytes((ushort)deviceVariableBytes.Length).Concat(deviceVariableBytes);
                })))
                yield return b;

            foreach (var keyValuePair in valueDictionary)
            {
                switch (keyValuePair.Key.DataType)
                {
                    case LSElectric.DataType.Bit:
                        foreach (var b in WordToLittleEndianBytes(1)) yield return b;
                        yield return (byte)(keyValuePair.Value.BitValue ? 1 : 0);
                        break;
                    case LSElectric.DataType.Byte:
                        foreach (var b in WordToLittleEndianBytes(1)) yield return b;
                        yield return keyValuePair.Value.ByteValue;
                        break;
                    case LSElectric.DataType.Word:
                        foreach (var b in WordToLittleEndianBytes(2)) yield return b;
                        foreach (var b in ValueToLittleEndianBytes(keyValuePair.Value.WordValue)) yield return b;
                        break;
                    case LSElectric.DataType.DoubleWord:
                        foreach (var b in WordToLittleEndianBytes(4)) yield return b;
                        foreach (var b in ValueToLittleEndianBytes(keyValuePair.Value.DoubleWordValue)) yield return b;
                        break;
                    case LSElectric.DataType.LongWord:
                        foreach (var b in WordToLittleEndianBytes(8)) yield return b;
                        foreach (var b in ValueToLittleEndianBytes(keyValuePair.Value.LongWordValue)) yield return b;
                        break;
                }
            }
        }
    }

    /// <summary>
    /// 연속 디바이스 변수 쓰기 요청
    /// </summary>
    public class FEnetWriteContinuousRequest : FEnetWriteRequest, IList<byte>, IContinuousAccessRequest
    {
        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="deviceType">읽기 요청 시작 디바이스</param>
        /// <param name="index">읽기 요청 시작 디바이스 인덱스</param>
        public FEnetWriteContinuousRequest(DeviceType deviceType, uint index) : this(deviceType, index, null) { }

        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="deviceType">읽기 요청 시작 디바이스</param>
        /// <param name="index">읽기 요청 시작 디바이스 인덱스</param>
        /// <param name="deviceValues">쓰기 요청할 디바이스 값들</param>
        public FEnetWriteContinuousRequest(DeviceType deviceType, uint index, IEnumerable<byte> deviceValues) : base(FEnetDataType.Continuous)
        {
            startDeviceVariable = new DeviceVariable(deviceType, LSElectric.DataType.Byte, index);

            if (deviceValues == null)
                this.deviceValues = new List<byte>();
            else
                this.deviceValues = new List<byte>(deviceValues);
        }

        /// <summary>
        /// 생성자
        /// </summary>
        /// <param name="deviceType">읽기 요청 시작 디바이스</param>
        /// <param name="index">읽기 요청 시작 디바이스 인덱스</param>
        /// <param name="value">쓰기 요청할 바이트 값</param>
        /// <param name="moreValues">추가 쓰기 요청할 바이트 값들</param>
        public FEnetWriteContinuousRequest(DeviceType deviceType, uint index, byte value, params byte[] moreValues)
            : this(deviceType, index, new byte[] { value }.Concat(moreValues)) { }

        /// <summary>
        /// 블록 수
        /// </summary>
        public override ushort BlockCount => 1;

        /// <summary>
        /// 요청 메시지 복제
        /// </summary>
        /// <returns>복제된 요청 메시지</returns>
        public override object Clone() => new FEnetWriteContinuousRequest(startDeviceVariable.DeviceType, startDeviceVariable.Index, deviceValues) { InvokeID = InvokeID, UseHexBitIndex = UseHexBitIndex };

        private readonly List<byte> deviceValues;

        private DeviceVariable startDeviceVariable;

        /// <summary>
        /// 쓰기 요청 시작 디바이스 변수
        /// </summary>
        public DeviceVariable StartDeviceVariable { get => startDeviceVariable; }

