# LS ELECTRIC XGT FEnet Protocol - Implementation Guide

Practical C# implementation patterns for XGT FEnet protocol based on VagabondK.Protocols.

---

## 1. BASIC FRAME STRUCTURE (C# Code)

### Header Class Pattern

```csharp
public class FEnetHeader
{
    public byte[] CompanyID { get; set; } // 10 bytes, ASCII
    public ushort InvokeID { get; set; }  // 2 bytes, little-endian
    public ushort DataLength { get; set; } // 2 bytes, little-endian
    public byte SourceOfFrame { get; set; } // 1 byte: 0x33=client, 0x11=server
    public bool UseChecksum { get; set; }

    public byte[] Serialize()
    {
        List<byte> header = new List<byte>(20);

        // Company ID (10 bytes, padded with zeros)
        byte[] companyIdBytes = Encoding.ASCII.GetBytes("LSIS-XGT");
        header.AddRange(companyIdBytes);
        header.AddRange(new byte[10 - companyIdBytes.Length]);

        // Reserved (3 bytes)
        header.AddRange(new byte[3]);

        // Source of Frame (1 byte)
        header.Add(SourceOfFrame);

        // Invoke ID (2 bytes, little-endian)
        header.AddRange(BitConverter.GetBytes(InvokeID));

        // Data Length (2 bytes, little-endian)
        header.AddRange(BitConverter.GetBytes(DataLength));

        // Reserved (1 byte)
        header.Add(0x00);

        // Checksum (1 byte)
        byte checksum = 0x00;
        if (UseChecksum)
            checksum = (byte)header.Take(19).Sum(b => b) % 256;
        header.Add(checksum);

        return header.ToArray();
    }

    public static FEnetHeader Deserialize(byte[] buffer)
    {
        if (buffer.Length < 20)
            throw new ArgumentException("Buffer too small for FEnet header");

        var header = new FEnetHeader
        {
            CompanyID = buffer.Skip(0).Take(10).ToArray(),
            SourceOfFrame = buffer[13],
            InvokeID = BitConverter.ToUInt16(buffer, 14),
            DataLength = BitConverter.ToUInt16(buffer, 16)
        };

        // Validate checksum if present
        byte expectedChecksum = (byte)buffer.Take(19).Sum(b => b) % 256;
        if (buffer[19] != 0x00 && buffer[19] != expectedChecksum)
            throw new InvalidOperationException("Checksum mismatch");

        return header;
    }
}
```

