## 3. CONTINUOUS READ RESPONSE PARSING

### Frame Parsing

```csharp
public class ReadContinuousResponse
{
    public ushort InvokeID { get; set; }
    public bool IsSuccess { get; set; }
    public ushort ErrorCode { get; set; }
    public byte[] Data { get; set; }

    public static ReadContinuousResponse Parse(byte[] buffer)
    {
        if (buffer.Length < 20)
            throw new ArgumentException("Buffer too small");

        // Parse header
        var invokeId = BitConverter.ToUInt16(buffer, 14);
        var dataLength = BitConverter.ToUInt16(buffer, 16);

        var response = new ReadContinuousResponse { InvokeID = invokeId };

        // Parse data frame (starts at offset 20)
        int offset = 20;

        // Command (should be 0x0055 = 0x0054 + 1)
        ushort command = BitConverter.ToUInt16(buffer, offset);
        offset += 2;

        // DataType (should be 0x0014)
        ushort dataType = BitConverter.ToUInt16(buffer, offset);
        offset += 2;

        // Reserved (2 bytes)
        offset += 2;

        // ErrorStatus (2 bytes)
        ushort errorStatus = BitConverter.ToUInt16(buffer, offset);
        offset += 2;

        if (errorStatus == 0xFFFF)
        {
            // NAK - error response
            response.IsSuccess = false;
            response.ErrorCode = BitConverter.ToUInt16(buffer, offset);
            offset += 2;
            response.Data = new byte[0];
        }
        else
        {
            // ACK - success response
            response.IsSuccess = true;

            // BlockCount (should be 0x0001)
            ushort blockCount = BitConverter.ToUInt16(buffer, offset);
            offset += 2;

            // Data Length (number of data bytes)
            ushort dataLen = BitConverter.ToUInt16(buffer, offset);
            offset += 2;

            // Extract data
            response.Data = buffer.Skip(offset).Take(dataLen).ToArray();
        }

        return response;
    }
}

// Usage
byte[] responseBuffer = receiveFromSocket();
var response = ReadContinuousResponse.Parse(responseBuffer);

if (response.IsSuccess)
{
    Console.WriteLine($"Read {response.Data.Length} bytes successfully");
    for (int i = 0; i < response.Data.Length; i++)
    {
        Console.WriteLine($"  Byte {i}: 0x{response.Data[i]:X2}");
    }
}
else
{
    Console.WriteLine($"Error: 0x{response.ErrorCode:X4}");
}
```

