## 4. CONTINUOUS WRITE REQUEST

### Frame Building

```csharp
public byte[] BuildWriteContinuousRequest(
    ushort invokeId,
    string deviceType,
    uint startAddress,
    byte[] dataToWrite)
{
    List<byte> frame = new List<byte>();

    // Command (0x0058 = Write)
    frame.AddRange(BitConverter.GetBytes((ushort)0x0058));

    // Data Type (0x0014 = Continuous)
    frame.AddRange(BitConverter.GetBytes((ushort)0x0014));

    // Reserved
    frame.AddRange(new byte[2]);

    // Block Count (0x0001)
    frame.AddRange(BitConverter.GetBytes((ushort)0x0001));

    // Device Variable
    byte[] deviceVarBytes = EncodeDeviceVariable(deviceType, startAddress);
    frame.AddRange(BitConverter.GetBytes((ushort)deviceVarBytes.Length));
    frame.AddRange(deviceVarBytes);

    // Count (number of bytes to write)
    frame.AddRange(BitConverter.GetBytes((ushort)dataToWrite.Length));

    // Data bytes
    frame.AddRange(dataToWrite);

    // Build header
    var header = new FEnetHeader
    {
        CompanyID = Encoding.ASCII.GetBytes("LSIS-XGT"),
        SourceOfFrame = 0x33,  // Client
        InvokeID = invokeId,
        DataLength = (ushort)frame.Count,
        UseChecksum = true
    };

    var headerBytes = header.Serialize();
    return headerBytes.Concat(frame).ToArray();
}

// Usage
byte[] dataToWrite = new byte[] { 0xAA, 0xBB, 0xCC, 0xDD, 0xEE };
byte[] writeRequest = BuildWriteContinuousRequest(
    invokeId: 3,
    deviceType: "M",
    startAddress: 0,
    dataToWrite: dataToWrite
);

socket.Send(writeRequest);
