## 9. THREADING CONSIDERATIONS

### Thread-Safe Operations

```csharp
public class ThreadSafeFEnetClient : IDisposable
{
    private readonly object lockObject = new object();
    private TcpClient socket;
    private NetworkStream stream;

    public byte[] SendRequest(byte[] request, int timeoutMs = 3000)
    {
        lock (lockObject)
        {
            if (!socket.Connected)
                throw new InvalidOperationException("Not connected");

            stream.Write(request, 0, request.Length);
            stream.Flush();

            return ReceiveResponse(timeoutMs);
        }
    }

    private byte[] ReceiveResponse(int timeoutMs)
    {
        socket.ReceiveTimeout = timeoutMs;

        byte[] headerBuffer = new byte[20];
        int read = stream.Read(headerBuffer, 0, 20);

        if (read != 20)
            throw new IOException("Incomplete header");

        ushort dataLength = BitConverter.ToUInt16(headerBuffer, 16);
        byte[] dataBuffer = new byte[dataLength];

        read = 0;
        while (read < dataLength)
        {
            int chunk = stream.Read(dataBuffer, read, dataLength - read);
            if (chunk == 0)
                throw new IOException("Connection closed");
            read += chunk;
        }

        return headerBuffer.Concat(dataBuffer).ToArray();
    }
}
