public static void LogFrame(byte[] frameData, string direction)
{
    Console.WriteLine($"{direction} ({frameData.Length} bytes):");

    for (int i = 0; i < frameData.Length; i += 16)
    {
        string hex = string.Join(" ",
            frameData.Skip(i).Take(16).Select(b => b.ToString("X2")));

        string offset = $"{i:X4}";
        Console.WriteLine($"{offset}: {hex}");
    }

    // Parse header
    if (frameData.Length >= 20)
    {
        var invokeId = BitConverter.ToUInt16(frameData, 14);
        var dataLen = BitConverter.ToUInt16(frameData, 16);
        Console.WriteLine($"InvokeID: {invokeId}, DataLen: {dataLen}");
    }
}

